function worked_http_ts_security_boundaries_2(scheme: string, hostAllowed: boolean, privateAddress: boolean, redirectAllowed: boolean): { accepted: boolean; reason: string } {
  if (scheme.toLowerCase() !== "https") return { accepted: false, reason: "scheme" };
  if (!hostAllowed || privateAddress) return { accepted: false, reason: "destination" };
  if (!redirectAllowed) return { accepted: false, reason: "redirect" };
  return { accepted: true, reason: "bounded authority" };
}

